import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar.tsx';
import { MenuPaper } from './components/MenuPaper.tsx';
import { LabelsPaper } from './components/LabelsPaper.tsx';
import { MenuItem } from './types.ts';
import { database } from './services/database.ts';
import { Printer } from 'lucide-react';

export default function App() {
  const [items, setItems] = useState<MenuItem[]>(() => database.loadItems());
  const [logo, setLogo] = useState<string | null>(null);
  const [menuBackground, setMenuBackground] = useState<string | null>(() => database.loadBackground());
  const [title, setTitle] = useState<string>('Coffee Break');
  const [notes, setNotes] = useState<string>(() => database.loadNotes());
  const [layoutMode, setLayoutMode] = useState<'menu' | 'labels' | 'labels-32'>('menu');

  useEffect(() => {
    database.saveItems(items);
  }, [items]);

  useEffect(() => {
    database.saveBackground(menuBackground);
  }, [menuBackground]);

  useEffect(() => {
    database.saveNotes(notes);
  }, [notes]);

  const handleToggleItem = (id: string) => {
    setItems(prev => prev.map(item => 
      item.id === id ? { ...item, selected: !item.selected } : item
    ));
  };

  const handleAddItem = (name: string) => {
    const newItem: MenuItem = {
      id: Date.now().toString(),
      name: name,
      selected: true
    };
    setItems(prev => [newItem, ...prev]);
  };

  const handleDeleteItem = (id: string) => {
    if (window.confirm('Excluir este prato?')) {
      setItems(prev => prev.filter(i => i.id !== id));
    }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setLogo(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleBackgroundUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setMenuBackground(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handlePrint = () => {
    window.focus();
    setTimeout(() => window.print(), 250);
  };

  if (!items) return <div className="p-10 text-center">Carregando...</div>;

  return (
    <div className="flex flex-col lg:flex-row min-h-screen bg-gray-100 font-sans">
      <Sidebar 
        items={items}
        onToggleItem={handleToggleItem}
        onAddItem={handleAddItem}
        onDeleteItem={handleDeleteItem}
        onLogoUpload={handleLogoUpload}
        onTitleChange={setTitle}
        currentTitle={title}
        notes={notes}
        onNotesChange={setNotes}
        layoutMode={layoutMode}
        onLayoutChange={setLayoutMode}
        onBackgroundUpload={handleBackgroundUpload}
        onClearBackground={() => setMenuBackground(null)}
        hasBackground={!!menuBackground}
      />

      <main className="flex-1 overflow-auto p-4 lg:p-12 flex flex-col items-center justify-start relative">
        <div className="relative flex flex-col lg:flex-row items-start gap-8">
          <div className="shadow-2xl bg-white print-area">
            {layoutMode === 'menu' ? (
                <MenuPaper 
                  logo={logo}
                  items={items}
                  title={title}
                  notes={notes}
                  backgroundImage={menuBackground}
                />
            ) : (
                <LabelsPaper 
                  logo={logo}
                  items={items}
                  mode={layoutMode}
                />
            )}
          </div>

          <div className="no-print lg:sticky lg:top-12 flex flex-col items-center gap-3 bg-white p-3 rounded-lg shadow-md border border-gray-100 min-w-[140px]">
            <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest">Ações</p>
            <button 
              onClick={handlePrint}
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded shadow flex items-center justify-center gap-2 transition-all"
            >
              <Printer size={16} />
              <span className="text-sm">IMPRIMIR</span>
            </button>
          </div>
        </div>
      </main>
    </div>
  );
}

