        <div className="flex-grow flex flex-col items-center justify-center w-full my-6">
          <div className="space-y-5 text-center w-full max-w-[80%]">
            {selectedItems.length > 0 ? selectedItems.map((item) => (
              <div 
                key={item.id} 
                className="text-xl font-bold uppercase tracking-[0.2em] leading-tight"
                style={{ fontFamily: "'Playfair Display', serif" }}
              >
                {item.name}
              </div>
            )) : (
              <p className="opacity-30 italic">Selecione itens na lateral...</p>
            )}
          </div>
        </div>

        {notes && (
            <div className="w-full max-w-[70%] text-center mt-6 pt-4 border-t-2 border-dotted opacity-70" style={{ borderColor: THEME_COLOR }}>
                <p className="text-sm italic font-serif whitespace-pre-wrap leading-relaxed">{notes}</p>
            </div>
        )}

        {!backgroundImage && (
            <div className="w-full flex items-end justify-between opacity-80 mt-12 pb-4">
                <div className="flex items-end">
                    <Wheat size={90} strokeWidth={1} style={{ transform: 'rotate(-15deg)' }} />
                </div>
                <div className="flex flex-col items-center opacity-40 pb-4">
                    <Utensils size={35} />
                    <span className="text-[10px] uppercase mt-2 tracking-[0.3em] font-bold">Bom Apetite</span>
                </div>
                <div className="flex items-end">
                    <ChefHat size={90} strokeWidth={1} style={{ transform: 'rotate(15deg)' }} />
                </div>
            </div>
        )}
      </div>
    </div>
  );
};
